mapper.select:
SELECT * FROM ( SELECT A.*, ROWNUM rnum FROM ( SELECT posting_id AS postingId, job_category AS jobCategory, company_name AS companyName, title, deadline, skills, post_type AS postType, posting_url AS postingUrl, createdate, contents FROM job_posting
(title LIKE '%' || #{keyword} || '%' OR company_name LIKE '%' || #{keyword} || '%' OR skills LIKE '%' || #{keyword} || '%')
AND job_category = #{category}
ORDER BY createdate DESC ) A WHERE ROWNUM <= #{offset} + #{pageSize} ) WHERE rnum > #{offset}

SELECT COUNT(*) FROM job_posting
(title LIKE '%' || #{keyword} || '%' OR company_name LIKE '%' || #{keyword} || '%' OR skills LIKE '%' || #{keyword} || '%')
AND job_category = #{category}

SELECT jp.posting_id AS postingId, jp.job_category AS jobCategory, jp.company_name AS companyName, jp.title, jp.deadline, jp.skills, jp.post_type AS postType, jp.posting_url AS postingUrl, jp.createdate, CASE WHEN si.target_id IS NOT NULL THEN 'Y' ELSE 'N' END AS is_fav FROM job_posting jp LEFT OUTER JOIN saved_item si ON si.target_type = 'JOB' AND si.target_id = TO_CHAR(jp.posting_id) AND si.user_id = #{userId}
(jp.title LIKE '%' || #{keyword} || '%' OR jp.company_name LIKE '%' || #{keyword} || '%' OR jp.skills LIKE '%' || #{keyword} || '%')
AND jp.job_category = #{category}
ORDER BY jp.createdate DESC
